client_script:
(() => {
  const SOURCE = 'pikt-instant-quote-form';
  const FIELD_NAMES = ['prospect_name','contact_email','phone','prospect_company','building_type','building_size','service_frequency','service_interest','bathroom_count_range'];
  const isEmbedded = () => {
    try {
      return new URLSearchParams(window.location.search || '').get('embedded') === '1';
    } catch (error) {
      return false;
    }
  };

  const getHeight = () => {
    const body = document.body;
    const docEl = document.documentElement;
    return Math.max(
      body ? body.scrollHeight : 0,
      body ? body.offsetHeight : 0,
      docEl ? docEl.scrollHeight : 0,
      docEl ? docEl.offsetHeight : 0
    );
  };

  const postToParent = (type, payload = {}) => {
    if (!isEmbedded() || window.parent === window) {
      return;
    }

    window.parent.postMessage({
      source: SOURCE,
      type,
      ...payload
    }, window.location.origin);
  };

  const postHeight = () => {
    postToParent('resize', { height: getHeight() });
  };

  const markEmbedded = () => {
    if (!isEmbedded()) {
      return;
    }
    document.body.setAttribute('data-pikt-embedded', '1');
    document.documentElement.setAttribute('data-pikt-embedded', '1');
  };

  const installSuccessBridge = () => {
    const webForm = frappe.web_form;
    if (!webForm || webForm.__pikt_quote_success_bridge_installed) {
      return;
    }

    const originalHandleSuccess = webForm.handle_success.bind(webForm);
    webForm.handle_success = (message) => {
      const requestName = (message && message.name) || (webForm.doc && webForm.doc.name) || '';
      const token = (message && message.public_funnel_token) || (webForm.doc && webForm.doc.public_funnel_token) || '';

      if (isEmbedded() && requestName && token) {
        postToParent('success', { request: requestName, token });
        return;
      }

      originalHandleSuccess(message);
    };

    webForm.__pikt_quote_success_bridge_installed = true;
  };

  const installResizeObserver = () => {
    if (!isEmbedded()) {
      return;
    }

    if (window.__pikt_quote_resize_observer_installed) {
      postHeight();
      return;
    }

    const target = document.querySelector('.web-form-container') || document.body;
    if (target && window.ResizeObserver) {
      const observer = new ResizeObserver(() => postHeight());
      observer.observe(target);
      window.__pikt_quote_resize_observer_installed = true;
    }

    window.setTimeout(() => postToParent('ready', { height: getHeight() }), 0);
    window.setTimeout(postHeight, 120);
    window.setTimeout(postHeight, 500);
  };

  frappe.web_form.after_load = () => {
    markEmbedded();
    installSuccessBridge();
    installResizeObserver();
  };

  FIELD_NAMES.forEach((fieldname) => {
    frappe.web_form.on(fieldname, () => {
      window.setTimeout(postHeight, 0);
    });
  });
})();

